## 2. The C++ stub – `pcapng_stubs.cpp`

```cpp
/* pcapng_stubs.cpp – C++ implementation of the OCaml bindings.
 *
 *   Build command (example with dune):
 *   -----------------------------
 *   (executable
 *    (name pcapng_stubs)
 *    (libraries libpcapng)                ; <-- whatever the C++ lib is called
 *    (foreign_stubs
 *     (language cxx)
 *     (names pcapng_stubs))
 *   )
 *
 *   If you compile manually:
 *   ------------------------
 *   c++ -std=c++17 -I$(ocamlc -where) -fPIC -shared -o libpcapng_stubs.so \
 *       -I/path/to/libpcapng/include pcapng_stubs.cpp -lpcapng
 *
 *   The resulting shared object can be linked with the OCaml code.
 */

#define CAML_NAME_SPACE               // avoid name clashes with C++ std::*
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

#include <cstdint>
#include <cstring>
#include <exception>
#include <memory>
#include <string>

// --------------------------------------------------------------------------
// 1.  The real C++ library API (replace with the actual libpcapng headers).
// --------------------------------------------------------------------------
/*  The following is a *minimal* mock‑up of the real API, just so the stub
 *  compiles without the actual library.  Delete it and include the real
 *  headers when you integrate the binding.
 */
namespace pcapng {
    struct Frame {
        std::int64_t   timestamp_ns;   // nanoseconds since epoch
        std::uint32_t  captured_len;
        std::uint32_t  original_len;
        const uint8_t* data;           // pointer to the captured bytes
    };
    class File {
    public:
        explicit File(const std::string& path) {
            // In real code: open the file, throw on error.
            if (path.empty())
                throw std::runtime_error("empty path");
        }
        ~File() { /* close file */ }

        // Simple forward iterator (mocked)
        class iterator {
            std::size_t pos_;
            std::size_t total_;
        public:
            iterator(std::size_t start, std::size_t total) : pos_(start), total_(total) {}
            iterator& operator++() { ++pos_; return *this; }
            bool operator!=(const iterator& other) const { return pos_ != other.pos_; }
            Frame operator*() const {
                // Return a fake frame – replace with real data extraction.
                static const uint8_t dummy[64] = {0};
                return Frame{ 1620000000000000000LL + pos_*1000000,
                              64, 64, dummy };
            }
        };
        iterator begin() const { return iterator(0, 10); }   // 10 frames in the mock
        iterator end()   const { return iterator(10, 10); }
    };
} // namespace pcapng

// --------------------------------------------------------------------------
// 2.  OCaml custom block that holds a pointer to pcapng::File.
// --------------------------------------------------------------------------
struct caml_pcapng_file {
    std::unique_ptr<pcapng::File> file;
};

static void caml_pcapng_finalize(value v) {
    caml_pcapng_file* p = reinterpret_cast<caml_pcapng_file*>(Data_custom_val(v));
    // unique_ptr destructor automatically deletes the C++ object.
    delete p;
}

static struct custom_operations caml_pcapng_ops = {
    "pcapng.file",               // identifier (must be unique)
    caml_pcapng_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* Allocate a new OCaml custom block wrapping a freshly opened pcapng::File.
 * Throws [Error] on failure.
 */
static value caml_pcapng_wrap_file(std::unique_ptr<pcapng::File> f) {
    CAMLparam0();
    CAMLlocal1(block);
    block = caml_alloc_custom(&caml_pcapng_ops, sizeof(caml_pcapng_file), 0, 1);
    caml_pcapng_file* p = reinterpret_cast<caml_pcapng_file*>(Data_custom_val(block));
    p->file = std::move(f);
    CAMLreturn(block);
}

/* ----------------------------------------------------------------------
 *  Helper: turn a C++ pcapng::Frame into an OCaml value of type [frame].
 * ---------------------------------------------------------------------- */
static value caml_pcapng_frame_of_cpp(const pcapng::Frame& frm) {
    CAMLparam0();
    CAMLlocal5(ocaml_frame, ts, cap_len, orig_len, data);

    // 1. timestamp : int64
    ts = caml_copy_int64(frm.timestamp_ns);

    // 2. captured_len : int
    cap_len = Val_int(frm.captured_len);   // fits in a 31‑bit OCaml int

    // 3. original_len : int
    orig_len = Val_int(frm.original_len);

    // 4. data : bytes
    data = caml_alloc_string(frm.captured_len);
    if (frm.captured_len > 0)
        memcpy(String_val(data), frm.data, frm.captured_len);

    // 5. build the record (order must match the .mli definition)
    ocaml_frame = caml_alloc(4, 0);   // 4 fields, tag 0 (records are tags)
    Store_field(ocaml_frame, 0, ts);
    Store_field(ocaml_frame, 1, cap_len);
    Store_field(ocaml_frame, 2, orig_len);
    Store_field(ocaml_frame, 3, data);

    CAMLreturn(ocaml_frame);
}

/* ----------------------------------------------------------------------
 *  OCaml primitives
 * ---------------------------------------------------------------------- */

extern "C" {

/*  open_file : string -> capture */
CAMLprim value caml_pcapng_open_file(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(res);
    const char* path = String_val(v_path);
    try {
        auto cpp_file = std::make_unique<pcapng::File>(std::string(path));
        res = caml_pcapng_wrap_file(std::move(cpp_file));
    } catch (const std::exception& ex) {
        caml_raise_with_string(*caml_named_value("Pcapng.Error"), ex.what());
    }
    CAMLreturn(res);
}

/*  close : capture -> unit */
CAMLprim value caml_pcapng_close(value v_cap) {
    CAMLparam1(v_cap);
    // The custom block’s finaliser will run automatically when the GC
    // collects the value.  Here we just clear the pointer so that further
    // use raises an exception.
    caml_pcapng_file* p = reinterpret_cast<caml_pcapng_file*>(Data_custom_val(v_cap));
    if (!p->file) caml_raise_with_string(*caml_named_value("Pcapng.Error"),
                                        "capture already closed");
    p->file.reset();   // destroys the C++ object now
    CAMLreturn(Val_unit);
}

/*  iter : capture -> (frame -> unit) -> unit */
CAMLprim value caml_pcapng_iter(value v_cap, value v_cb) {
    CAMLparam2(v_cap, v_cb);
    caml_release_runtime_system();   // release OCaml lock while we walk C++ iterator
    caml_acquire_runtime_system();   // we will reacquire before each callback

    caml_pcapng_file* p = reinterpret_cast<caml_pcapng_file*>(Data_custom_val(v_cap));
    if (!p->file) caml_failwith("Pcapng.iter: capture already closed");

    try {
        for (auto it = p->file->begin(); it != p->file->end(); ++it) {
            const pcapng::Frame& cpp_frm = *it;
            value ocaml_frm = caml_pcapng_frame_of_cpp(cpp_frm);
            // Call the user callback.  Use caml_callback_exn to catch OCaml
            // exceptions and re‑raise them as OCaml errors.
            caml_release_runtime_system();   // allow other threads while we run OCaml code
            value result = caml_callback_exn(v_cb, ocaml_frm);
            caml_acquire_runtime_system();
            if (Is_exception_result(result)) {
                // Propagate the exception to the caller of iter.
                caml_raise(result);
            }
        }
    } catch (const std::exception& ex) {
        caml_acquire_runtime_system();
        caml_raise_with_string(*caml_named_value("Pcapng.Error"), ex.what());
    }
    CAMLreturn(Val_unit);
}

/*  fold : capture -> ('a -> frame -> 'a) -> 'a -> 'a */
CAMLprim value caml_pcapng_fold(value v_cap, value v_f, value v_acc) {
    CAMLparam3(v_cap, v_f, v_acc);
    CAMLlocal1(v_res);
    caml_pcapng_file* p = reinterpret_cast<caml_pcapng_file*>(Data_custom_val(v_cap));
    if (!p->file) caml_failwith("Pcapng.fold: capture already closed");

    v_res = v_acc;          // current accumulator
    try {
        for (auto it = p->file->begin(); it != p->file->end(); ++it) {
            const pcapng::Frame& cpp_frm = *it;
            value ocaml_frm = caml_pcapng_frame_of_cpp(cpp_frm);
            // callback : 'a -> frame -> 'a
            caml_release_runtime_system();
            value tmp = caml_callback_exn(v_f, v_res, ocaml_frm);
            caml_acquire_runtime_system();
            if (Is_exception_result(tmp))
                caml_raise(tmp);
            v_res = tmp;   // new accumulator
        }
    } catch (const std::exception& ex) {
        caml_acquire_runtime_system();
        caml_raise_with_string(*caml_named_value("Pcapng.Error"), ex.what());
    }
    CAMLreturn(v_res);
}

/*  to_seq : capture -> frame Seq.t */
CAMLprim value caml_pcapng_to_seq(value v_cap) {
    CAMLparam1(v_cap);
    CAMLlocal1(v_seq);

    // The sequence we build is a closure that holds a copy of the C++ iterator.
    // We store the iterator state in a custom block so that GC can free it.
    struct seq_state {
        std::unique_ptr<pcapng::File> file;
        std::unique_ptr<pcapng::File::iterator> it;
        std::unique_ptr<pcapng::File::iterator> end;
        bool exhausted;
        seq_state(std::unique_ptr<pcapng::File> f)
            : file(std::move(f)), exhausted(false) {
            it   = std::make_unique<pcapng::File::iterator>(file->begin());
            end  = std::make_unique<pcapng::File::iterator>(file->end());
        }
    };

    // Allocate a custom block that holds the seq_state
    caml_pcapng_file* p = reinterpret_cast<caml_pcapng_file*>(Data_custom_val(v_cap));
    if (!p->file) caml_failwith("Pcapng.to_seq: capture already closed");

    // Duplicate the underlying file object for the sequence (so that the
    // original capture can be closed independently).  The copy is cheap
    // because the C++ library typically shares the same underlying file
    // descriptor.
    auto file_copy = std::make_unique<pcapng::File>(*p->file);
    seq_state* st = new seq_state(std::move(file_copy));

    // The closure that implements the sequence generator
    value gen_closure = caml_alloc_closure(1, 0);
    Store_field(gen_closure, 0, caml_copy_intptr((intptr_t)st));

    // The generator function (called by Seq.unfold)
    static value seq_next(value v_state) {
        CAMLparam1(v_state);
        CAMLlocal1(v_res);
        seq_state* st = (seq_state*)caml_copy_intptr_val(v_state);
        if (st->exhausted) {
            v_res = Val_int(0);          // None
        } else {
            if (*(st->it) == *(st->end)) {
                st->exhausted = true;
                v_res = Val_int(0);      // None
            } else {
                const pcapng::Frame& cpp_frm = *(*(st->it));
                value ocaml_frm = caml_pcapng_frame_of_cpp(cpp_frm);
                // Some ocaml_frm
                v_res = caml_alloc(2, 0);
                Store_field(v_res, 0, ocaml_frm);
                // The state (same pointer) for the next call
                Store_field(v_res, 1, v_state);
                ++(*(st->it));
            }
        }
        CAMLreturn(v_res);
    }

    // Register the generator as a closure (Seq.unfold uses a function of type
    // 'state -> (a * state) option)
    v_seq = caml_alloc(2, 0);
    Store_field(v_seq, 0, gen_closure);               // the generator function
    Store_field(v_seq, 1, gen_closure);               // its argument (the state)

    // The finaliser for the seq_state
    static void seq_state_finalize(value v) {
        seq_state* st = (seq_state*)caml_copy_intptr_val(v);
        delete st;
    }
    // Attach finaliser to the closure so GC frees the C++ iterator.
    caml_register_custom_operations(&caml_pcapng_ops);
    caml_register_generational_custom_operations(&caml_pcapng_ops);
    caml_register_custom_finalizer(gen_closure, seq_state_finalize);

    CAMLreturn(v_seq);
}

/* ----------------------------------------------------------------------
 *  Register the custom exception value “Pcapng.Error”.
 * ---------------------------------------------------------------------- */
CAMLprim value caml_pcapng_register_exn(value unit) {
    CAMLparam1(unit);
    static const char* const name = "Pcapng.Error";
    caml_register_named_value(name);
    CAMLreturn(Val_unit);
}
} // extern "C"
```

