## 3. How to compile & use the binding

### 3.1. Directory layout

```
src/
│─ pcapng.mli
│─ pcapng.ml          (tiny wrapper that just opens the exception name)
│─ pcapng_stubs.cpp
```

### 3.2. Minimal `pcapng.ml`

```ocaml
(* pcapng.ml – just expose the exception name to the stub *)
exception Error of string

let () = Callback.register_exception "Pcapng.Error" (Error "")
```

### 3.3. Dune file (recommended)

```dune
(library
 (name pcapng)
 (public_name pcapng)
 (modules pcapng)
 (foreign_stubs
  (language cxx)
  (names pcapng_stubs))
 (libraries libpcapng)        ; <-- whatever the C++ lib is called
 (cxx_flags (:standard -std=c++17))
 (c_flags (:standard -Wall -Wextra))
)
```

If you are not using **dune**, a manual compilation line (Linux/macOS) looks like:

```sh
ocamlc -c -I +ocaml pcapng.mli
ocamlopt -c pcapng.ml
c++ -std=c++17 -fPIC -I$(ocamlc -where) -I/path/to/libpcapng/include \
    -c pcapng_stubs.cpp
c++ -shared -o libpcapng_stubs.so pcapng_stubs.o -lpcapng
ocamlopt -output-obj -o libpcapng.o pcapng.cmx
ocamlopt -ccopt -L. -cclib -lpcapng_stubs -o pcapng.cmx libpcapng.o
```

Now you can use the library from OCaml:

```ocaml
(* example.ml *)
let () =
  let cap = Pcapng.open_file "sample.pcapng" in
  (* 1) simple iteration *)
  Pcapng.iter cap (fun frm ->
      Printf.printf "Got %d‑byte frame at %Ld ns\n"
        frm.captured_len frm.timestamp);
  (* 2) folding *)
  let total_bytes =
    Pcapng.fold cap (fun acc frm -> acc + frm.captured_len) 0
  in
  Printf.printf "Total captured bytes: %d\n" total_bytes;
  (* 3) using Seq.t *)
  let seq = Pcapng.to_seq cap in
  Seq.iter (fun frm ->
      (* do something with each frame *)
      ()) seq;
  Pcapng.close cap
```

Compile the example with the library you just built, and you have a fully‑functional OCaml API that walks over the C++ iterator **while allowing user‑supplied OCaml callbacks**.

